import time
import base64
import pyotp
import qrcode
from io import BytesIO
from PIL import Image

def generate_secret():
    return base64.b32encode(pyotp.random_base32().encode()).decode()

def generate_qr_code(user, host, secret):
    otp_auth_url = pyotp.totp.TOTP(secret).provisioning_uri(user, issuer_name=host)
    qr = qrcode.QRCode(error_correction=qrcode.constants.ERROR_CORRECT_H)
    qr.add_data(otp_auth_url)
    qr.make(fit=True)
    img = qr.make_image(fill='black', back_color='white')
    img_byte_arr = BytesIO()
    img.save(img_byte_arr, format='PNG')
    img_byte_arr = img_byte_arr.getvalue()
    return img_byte_arr

def validate_totp(totp_token, secret):
    return pyotp.TOTP(secret).verify(totp_token)

# Example usage
secret = generate_secret()

# Generate QR code
qr_img_bytes = generate_qr_code('test_user', 'test_host', secret)

# You can save the QR code to a file
with open("test_qr.png", "wb") as f:
    f.write(qr_img_bytes)

# Validate TOTP
user_totp = '123456' # input received from user
is_valid = validate_totp(user_totp, secret)
print(is_valid)